mapper.select:
SELECT f.* FROM fund f

    INNER JOIN fund_tag_relation r ON f.fund_code = r.fund_code



        AND r.tag_id = #{tagId}


        AND (f.fund_code LIKE CONCAT('%', #{keyword}, '%')
        OR f.fund_name LIKE CONCAT('%', #{keyword}, '%'))


        AND f.fund_type = #{fundType}


        AND f.status = #{status}


ORDER BY f.fund_code
